[[
    Freestyle Hub v1.0
    by Freestyle 👾
]]

local Players=game:GetService("Players")local UserInputService=game:GetService("UserInputService")local TweenService=game:GetService("TweenService")local RunService=game:GetService("RunService")local player=Players.LocalPlayer local character=player.Character or player.CharacterAdded:Wait()local humanoid=character:WaitForChild("Humanoid")local rootPart=character:WaitForChild("HumanoidRootPart")local flingEnabled,ragdollEnabled,flyEnabled,espEnabled,walkSpeedValue,originalWalkSpeed=false,false,false,false,16,16 local flying,flySpeed,bodyVelocity,bodyGyro=false,50,nil,nil local screenGui=Instance.new("ScreenGui")screenGui.Name="FreestyleHub"screenGui.Parent=player.PlayerGui local mainFrame=Instance.new("Frame")mainFrame.Name="MainFrame"mainFrame.Size=UDim2.new(0,400,0,500)mainFrame.Position=UDim2.new(0.5,-200,0.5,-250)mainFrame.BackgroundColor3=Color3.fromRGB(20,20,25)mainFrame.BackgroundTransparency=0.05mainFrame.BorderSizePixel=0mainFrame.Parent=screenGui local corner=Instance.new("UICorner")corner.CornerRadius=UDim.new(0,12)corner.Parent=mainFrame local shadow=Instance.new("UIStroke")shadow.Color=Color3.fromRGB(0,150,255)shadow.Thickness=2shadow.Transparency=0.5shadow.Parent=mainFrame local titleBar=Instance.new("Frame")titleBar.Name="TitleBar"titleBar.Size=UDim2.new(1,0,0,40)titleBar.BackgroundColor3=Color3.fromRGB(25,25,35)titleBar.BackgroundTransparency=0.3titleBar.BorderSizePixel=0titleBar.Parent=mainFrame local titleCorner=Instance.new("UICorner")titleCorner.CornerRadius=UDim.new(0,12)titleCorner.Parent=titleBar local titleLabel=Instance.new("TextLabel")titleLabel.Name="TitleLabel"titleLabel.Size=UDim2.new(0.7,0,1,0)titleLabel.Position=UDim2.new(0.05,0,0,0)titleLabel.BackgroundTransparency=1titleLabel.Text="Made by Freestyle 👾"titleLabel.TextColor3=Color3.fromRGB(0,200,255)titleLabel.TextScaled=truetitleLabel.Font=Enum.Font.GothamBlacktitleLabel.TextXAlignment=Enum.TextXAlignment.LefttitleLabel.Parent=titleBar local minimizeButton=Instance.new("TextButton")minimizeButton.Name="MinimizeButton"minimizeButton.Size=UDim2.new(0,30,0,30)minimizeButton.Position=UDim2.new(0.85,0,0.125,0)minimizeButton.BackgroundColor3=Color3.fromRGB(40,40,50)minimizeButton.BackgroundTransparency=0.5minimizeButton.BorderSizePixel=0minimizeButton.Text="−"minimizeButton.TextColor3=Color3.fromRGB(200,200,200)minimizeButton.TextSize=20minimizeButton.Font=Enum.Font.GothamBoldminimizeButton.Parent=titleBar local minCorner=Instance.new("UICorner")minCorner.CornerRadius=UDim.new(0,6)minCorner.Parent=minimizeButton local closeButton=Instance.new("TextButton")closeButton.Name="CloseButton"closeButton.Size=UDim2.new(0,30,0,30)closeButton.Position=UDim2.new(0.925,0,0.125,0)closeButton.BackgroundColor3=Color3.fromRGB(200,50,50)closeButton.BackgroundTransparency=0.3closeButton.BorderSizePixel=0closeButton.Text="✕"closeButton.TextColor3=Color3.fromRGB(255,255,255)closeButton.TextSize=16closeButton.Font=Enum.Font.GothamBoldcloseButton.Parent=titleBar local closeCorner=Instance.new("UICorner")closeCorner.CornerRadius=UDim.new(0,6)closeCorner.Parent=closeButton local scrollView=Instance.new("ScrollingFrame")scrollView.Name="ScrollView"scrollView.Size=UDim2.new(1,-20,1,-60)scrollView.Position=UDim2.new(0,10,0,50)scrollView.BackgroundTransparency=1scrollView.BorderSizePixel=0scrollView.ScrollBarThickness=4scrollView.ScrollBarImageColor3=Color3.fromRGB(0,150,255)scrollView.Parent=mainFrame local scrollLayout=Instance.new("UIListLayout")scrollLayout.Padding=UDim.new(0,8)scrollLayout.SortOrder=Enum.SortOrder.LayoutOrderscrollLayout.Parent=scrollView

local function createButton(text,callback,icon)local button=Instance.new("TextButton")button.Size=UDim2.new(1,0,0,40)button.BackgroundColor3=Color3.fromRGB(30,30,40)button.BackgroundTransparency=0.3button.BorderSizePixel=0button.Text=textbutton.TextColor3=Color3.fromRGB(200,200,200)button.TextSize=16button.Font=Enum.Font.GothamSemiboldbutton.AutoButtonColor=falsebutton.Parent=scrollView local btnCorner=Instance.new("UICorner")btnCorner.CornerRadius=UDim.new(0,8)btnCorner.Parent=button local btnStroke=Instance.new("UIStroke")btnStroke.Color=Color3.fromRGB(0,150,255)btnStroke.Thickness=1btnStroke.Transparency=0.7btnStroke.Parent=button if icon then local iconLabel=Instance.new("TextLabel")iconLabel.Size=UDim2.new(0,30,1,0)iconLabel.Position=UDim2.new(0,5,0,0)iconLabel.BackgroundTransparency=1iconLabel.Text=iconiconLabel.TextColor3=Color3.fromRGB(0,200,255)iconLabel.TextSize=18iconLabel.Font=Enum.Font.GothamBoldiconLabel.Parent=button end button.MouseEnter:Connect(function()TweenService:Create(button,TweenInfo.new(0.2),{BackgroundColor3=Color3.fromRGB(40,40,60),BackgroundTransparency=0.1}):Play()end)button.MouseLeave:Connect(function()TweenService:Create(button,TweenInfo.new(0.2),{BackgroundColor3=Color3.fromRGB(30,30,40),BackgroundTransparency=0.3}):Play()end)button.MouseButton1Click:Connect(callback)return button end

local function createToggle(text,callback,icon)local toggle=Instance.new("TextButton")toggle.Size=UDim2.new(1,0,0,40)toggle.BackgroundColor3=Color3.fromRGB(30,30,40)toggle.BackgroundTransparency=0.3toggle.BorderSizePixel=0toggle.Text=text.." [OFF]"toggle.TextColor3=Color3.fromRGB(200,200,200)toggle.TextSize=16toggle.Font=Enum.Font.GothamSemiboldtoggle.AutoButtonColor=falsetoggle.Parent=scrollView local toggleCorner=Instance.new("UICorner")toggleCorner.CornerRadius=UDim.new(0,8)toggleCorner.Parent=toggle local toggleStroke=Instance.new("UIStroke")toggleStroke.Color=Color3.fromRGB(0,150,255)toggleStroke.Thickness=1toggleStroke.Transparency=0.7toggleStroke.Parent=toggle if icon then local iconLabel=Instance.new("TextLabel")iconLabel.Size=UDim2.new(0,30,1,0)iconLabel.Position=UDim2.new(0,5,0,0)iconLabel.BackgroundTransparency=1iconLabel.Text=iconiconLabel.TextColor3=Color3.fromRGB(0,200,255)iconLabel.TextSize=18iconLabel.Font=Enum.Font.GothamBoldiconLabel.Parent=toggle end local state=falsetoggle.MouseEnter:Connect(function()TweenService:Create(toggle,TweenInfo.new(0.2),{BackgroundColor3=Color3.fromRGB(40,40,60),BackgroundTransparency=0.1}):Play()end)toggle.MouseLeave:Connect(function()TweenService:Create(toggle,TweenInfo.new(0.2),{BackgroundColor3=Color3.fromRGB(30,30,40),BackgroundTransparency=0.3}):Play()end)toggle.MouseButton1Click:Connect(function()state=not state toggle.Text=text..(state and" [ON]"or" [OFF]")toggle.TextColor3=state and Color3.fromRGB(0,255,200)or Color3.fromRGB(200,200,200)callback(state)end)return toggle end

local function createSlider(text,min,max,default,callback)local container=Instance.new("Frame")container.Size=UDim2.new(1,0,0,60)container.BackgroundTransparency=1container.Parent=scrollView local label=Instance.new("TextLabel")label.Size=UDim2.new(1,0,0,20)label.BackgroundTransparency=1label.Text=text..": "..tostring(default)label.TextColor3=Color3.fromRGB(200,200,200)label.TextSize=14label.Font=Enum.Font.GothamSemiboldlabel.Parent=container local slider=Instance.new("Frame")slider.Size=UDim2.new(1,0,0,20)slider.Position=UDim2.new(0,0,0,25)slider.BackgroundColor3=Color3.fromRGB(40,40,50)slider.BorderSizePixel=0slider.Parent=container local sliderCorner=Instance.new("UICorner")sliderCorner.CornerRadius=UDim.new(0,10)sliderCorner.Parent=slider local fill=Instance.new("Frame")fill.Size=UDim2.new((default-min)/(max-min),0,1,0)fill.BackgroundColor3=Color3.fromRGB(0,150,255)fill.BorderSizePixel=0fill.Parent=slider local fillCorner=Instance.new("UICorner")fillCorner.CornerRadius=UDim.new(0,10)fillCorner.Parent=fill local value=default local function updateSlider(input)local relativeX=math.clamp((input.Position.X-slider.AbsolutePosition.X)/slider.AbsoluteSize.X,0,1)value=min+(max-min)*relativeX value=math.round(value)fill.Size=UDim2.new((value-min)/(max-min),0,1,0)label.Text=text..": "..tostring(value)callback(value)end slider.InputBegan:Connect(function(input)if input.UserInputType==Enum.UserInputType.MouseButton1 then updateSlider(input)local connection connection=UserInputService.InputChanged:Connect(function(inputChanged)if inputChanged.UserInputType==Enum.UserInputType.MouseMovement then updateSlider(inputChanged)end end)UserInputService.InputEnded:Connect(function(inputEnded)if inputEnded.UserInputType==Enum.UserInputType.MouseButton1 then connection:Disconnect()end end)end end)end

local function getTargetPlayer()local target=nil local minDistance=math.huge for _,otherPlayer in pairs(Players:GetPlayers())do if otherPlayer~=player then local otherChar=otherPlayer.Character if otherChar and otherChar:FindFirstChild("HumanoidRootPart")then local distance=(rootPart.Position-otherChar.HumanoidRootPart.Position).Magnitude if distance<minDistance then minDistance=distance target=otherPlayer end end end end return target end

local function mostrarNotificacao(texto)local notification=Instance.new("Frame")notification.Size=UDim2.new(0,300,0,50)notification.Position=UDim2.new(0.5,-150,0.9,0)notification.BackgroundColor3=Color3.fromRGB(20,20,30)notification.BackgroundTransparency=0.1notification.BorderSizePixel=0notification.Parent=screenGui local notCorner=Instance.new("UICorner")notCorner.CornerRadius=UDim.new(0,10)notCorner.Parent=notification local notStroke=Instance.new("UIStroke")notStroke.Color=Color3.fromRGB(0,150,255)notStroke.Thickness=1notStroke.Transparency=0.5notStroke.Parent=notification local label=Instance.new("TextLabel")label.Size=UDim2.new(1,0,1,0)label.BackgroundTransparency=1label.Text=textolabel.TextColor3=Color3.fromRGB(255,255,255)label.TextSize=16label.Font=Enum.Font.GothamSemiboldlabel.Parent=notification notification:TweenPosition(UDim2.new(0.5,-150,0.85,0),"Out","Quad",0.3,true)task.wait(2)notification:TweenPosition(UDim2.new(0.5,-150,0.9,0),"In","Quad",0.3,true)task.wait(0.3)notification:Destroy()end

local function ativarVoo()if flying then return end flying=true bodyVelocity=Instance.new("BodyVelocity")bodyVelocity.MaxForce=Vector3.new(10000,10000,10000)bodyVelocity.Parent=rootPart bodyGyro=Instance.new("BodyGyro")bodyGyro.MaxTorque=Vector3.new(10000,10000,10000)bodyGyro.CFrame=rootPart.CFramebodyGyro.Parent=rootPart local flyConnection flyConnection=RunService.Heartbeat:Connect(function()if not flying then flyConnection:Disconnect()return end local moveDirection=Vector3.new()local forward=rootPart.CFrame.LookVector local right=rootPart.CFrame.RightVector local up=Vector3.new(0,1,0)if UserInputService:IsKeyDown(Enum.KeyCode.W)then moveDirection=moveDirection+forward end if UserInputService:IsKeyDown(Enum.KeyCode.S)then moveDirection=moveDirection-forward end if UserInputService:IsKeyDown(Enum.KeyCode.A)then moveDirection=moveDirection-right end if UserInputService:IsKeyDown(Enum.KeyCode.D)then moveDirection=moveDirection+right end if UserInputService:IsKeyDown(Enum.KeyCode.Space)then moveDirection=moveDirection+up end if UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)then moveDirection=moveDirection-up end if moveDirection.Magnitude>0 then moveDirection=moveDirection.Unit*flySpeed end bodyVelocity.Velocity=moveDirection bodyGyro.CFrame=rootPart.CFrame end)end

local function desativarVoo()flying=false if bodyVelocity then bodyVelocity:Destroy()end if bodyGyro then bodyGyro:Destroy()end end

local espObjects={}
local function ativarESP()for _,otherPlayer in pairs(Players:GetPlayers())do if otherPlayer~=player then local otherChar=otherPlayer.Character if otherChar and otherChar:FindFirstChild("HumanoidRootPart")then local espBox=Instance.new("BoxHandleAdornment")espBox.Size=Vector3.new(4,6,2)espBox.Color3=Color3.fromRGB(0,255,0)espBox.Transparency=0.5espBox.ZIndex=10espBox.AlwaysOnTop=true espBox.Parent=otherChar.HumanoidRootPart table.insert(espObjects,espBox)local espLabel=Instance.new("BillboardGui")espLabel.Size=UDim2.new(0,100,0,30)espLabel.Adornee=otherChar.HumanoidRootPart espLabel.Parent=otherChar.HumanoidRootPart local nameLabel=Instance.new("TextLabel")nameLabel.Size=UDim2.new(1,0,1,0)nameLabel.BackgroundTransparency=1nameLabel.Text=otherPlayer.NamenameLabel.TextColor3=Color3.fromRGB(0,255,255)nameLabel.TextSize=14nameLabel.Font=Enum.Font.GothamBoldnameLabel.Parent=espLabel table.insert(espObjects,espLabel)end end end end

local function desativarESP()for _,obj in pairs(espObjects)do obj:Destroy()end espObjects={}end

createToggle("Fling",function(state)flingEnabled=state if state then local bodyVelocity=Instance.new("BodyVelocity")bodyVelocity.MaxForce=Vector3.new(4000,4000,4000)bodyVelocity.Velocity=Vector3.new(0,0,0)bodyVelocity.Parent=rootPart local flingConnection=RunService.Heartbeat:Connect(function()if not flingEnabled then bodyVelocity:Destroy()flingConnection:Disconnect()return end for _,otherPlayer in pairs(Players:GetPlayers())do if otherPlayer~=player then local otherChar=otherPlayer.Character if otherChar and otherChar:FindFirstChild("HumanoidRootPart")then local otherRoot=otherChar.HumanoidRootPart local distance=(rootPart.Position-otherRoot.Position).Magnitude if distance<15 then local direction=(otherRoot.Position-rootPart.Position).Unit bodyVelocity.Velocity=direction*150 end end end end end)end mostrarNotificacao("Fling "..(state and"ativado"or"desativado"))end,"💥")

createToggle("Ragdoll",function(state)ragdollEnabled=state if state then humanoid.PlatformStand=true else humanoid.PlatformStand=false end mostrarNotificacao("Ragdoll "..(state and"ativado"or"desativado"))end,"🧍")

createButton("Teleport (TP)",function()local target=getTargetPlayer()if target then local targetChar=target.Character if targetChar and targetChar:FindFirstChild("HumanoidRootPart")then rootPart.CFrame=targetChar.HumanoidRootPart.CFrame*CFrame.new(0,2,0)mostrarNotificacao("Teleportado para "..target.Name)end else mostrarNotificacao("Nenhum jogador selecionado!")end end,"📍")

createToggle("Fly",function(state)flyEnabled=state if state then ativarVoo()else desativarVoo()end mostrarNotificacao("Fly "..(state and"ativado"or"desativado"))end,"✈️")

createToggle("ESP",function(state)espEnabled=state if state then ativarESP()else desativarESP()end mostrarNotificacao("ESP "..(state and"ativado"or"desativado"))end,"👁️")

createButton("Kill",function()local target=getTargetPlayer()if target then local targetChar=target.Character if targetChar and targetChar:FindFirstChild("Humanoid")then targetChar.Humanoid.Health=0 mostrarNotificacao(target.Name.." eliminado!")end else mostrarNotificacao("Nenhum jogador selecionado!")end end,"⚔️")

createSlider("WalkSpeed",16,100,16,function(value)walkSpeedValue=value humanoid.WalkSpeed=value mostrarNotificacao("WalkSpeed: "..tostring(value))end)

local dragging,dragStart,startPos=false,nil,nil titleBar.InputBegan:Connect(function(input)if input.UserInputType==Enum.UserInputType.MouseButton1 then dragging=true dragStart=input.Position startPos=mainFrame.Position end end)UserInputService.InputChanged:Connect(function(input)if dragging and input.UserInputType==Enum.UserInputType.MouseMovement then local delta=input.Position-dragStart mainFrame.Position=UDim2.new(startPos.X.Scale,startPos.X.Offset+delta.X,startPos.Y.Scale,startPos.Y.Offset+delta.Y)end end)UserInputService.InputEnded:Connect(function(input)if input.UserInputType==Enum.UserInputType.MouseButton1 then dragging=false end end)

local minimized=false minimizeButton.MouseButton1Click:Connect(function()minimized=not minimized if minimized then mainFrame:TweenSize(UDim2.new(0,400,0,40),"Out","Quad",0.3,true)else mainFrame:TweenSize(UDim2.new(0,400,0,500),"Out","Quad",0.3,true)end end)

closeButton.MouseButton1Click:Connect(function()screenGui:Destroy()end)

UserInputService.InputBegan:Connect(function(input,gameProcessed)if gameProcessed then return end if input.KeyCode==Enum.KeyCode.RightAlt then screenGui.Enabled=not screenGui.Enabled mostrarNotificacao(screenGui.Enabled and"Menu aberto"or"Menu fechado")end end)

mostrarNotificacao("Freestyle Hub carregado! 👾")
